  for (const service in services) {
    if (services[service].ports) {
      for (const port in services[service].ports) {
        const containerPort = services[service].ports[port].split(':')[0];
        const hostPort = services[service].ports[port].split(':')[1];
        if (service.toLowerCase() !== service || containerPort.toLowerCase() !== hostPort.toLowerCase()) {
          return false;
        }
      }
    }
  }
  return true;
}

