class Solution:
  def validate_ports_mapping(self, yaml_config: str) -> bool:
    import yaml
    yaml_config = yaml.safe_load(yaml_config)
    services = yaml_config['services']
    for service in services:
      if services[service].ports:
        for port in services[service].ports:
          container_port, host_port = services[service].ports[port].split(':')
          service_name = service.lower()
          container_port = container_port.lower()
          host_port = host_port.lower()
          if service_name !== container_port or service_name !== host_port:
            return False
    return True
